import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [4, 4, 2, 2, 1, 1, 3, 3, 1, 2, 2, 1, 2, 3, 4, 3, 4, 3, 2, 1, 4, 2, 3, 2, 2, 2, 2, 1, 3, 2, 3, 1, 1, 1, 2, 1, 3, 2, 2, 3, 2, 1, 2, 2, 2, 2, 3, 1, 1, 1, 2, 3, 4, 2, 3, 3, 1, 3, 3, 2, 2, 1, 2, 2, 3, 2, 1, 1, 3, 2, 3, 2, 1, 3, 2, 3, 1, 1, 1, 2, 2, 1, 3, 2, 2, 1, 2, 4, 1, 1, 1, 4, 1, 1, 1, 2, 1, 2, 2, 2];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `In a certain code, LAMP is written as ODPS. How will BOOK be written?`, o: [`DRRM`, `CQQM`, `CQQN`, `ERRN`], e: `LogiIcD: Letters are incTrIeTaLsEing + 3 plaLcAeN. GUAGE SUBJECT CATEGORY EXAMS MARKS (MINS) ID For, LAMP - ODPS AT AT PA L + 3 = O, A + 3 = D, M + 3 = P, P + 3 = S BOOK - ? Post Selection 17, 2026, 27, 2026, B + 3 = E, O + 3(M= aRt,riOcu+la3tio=n)R, K + 3 = N Post 18:44:05 21:42:25 So, BOOK is writtSeinmailsarERPaRpNer. Thus, correct optio(Hneilsd(odn). 24 Post Selection 17, 2026, 28, 2026,` },
  { s: `General Intelligence`, q: `Find the odd number.`, o: [`16`, `25`, `36`, `48`], e: `Now, we check each options. Option (a): 16 = 42(Perfect square) Option (b): 25 = 52(Perfect square) Option (c): 36 = 62(Perfect square) Option (d): 48 = Not a perfect square Three numbers (16, 25, 36) are perfect squares, but 48 is not. So, 48 is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Find the missing term in the series: A1, C3, E5, ___ , I9`, o: [`F6`, `G7`, `H8`, `G9`], e: `Given: A1, C3, E5, ___ , I9 Logic: Letters and numbers are increasing + 2 place. A + 2 = C, C + 2 = E, E + 2 = G, G + 2 = I 1 + 2 = 3, 3 + 2 = 5, 5 + 2 = 7, 7 + 2 = 9 So, the missing term is G7. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `A team is behind schedule on a critical project. What is the most effective first step?`, o: [`Add more tasks`, `Review and prioritize key activities`, `Cancel the project`, `Reduce quality standards`], e: `Given: A team is behind schedule on a critical project. Explanation: When a project is behind schedule, the most effective first step is to review the current work and prioritize the most critical activities so efforts are focused where they matter most. So, Review and prioritize key activities is the most effective first step. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `A man walks 6 km south, then 8 km west. How far is he from the starting point?`, o: [`10 km`, `12 km`, `14 km`, `8 km`], e: `Given: A man walks 6 km south, then 8 km west. From the given information path diagram will be. Using Pythagoras theorem: Distance: = 62 + 8 2 = 36 + 64 = 100 = 10km So, he is far 10km from the starting point. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `AB12 is related to CD34 in a certain way. In the same way, EF56 is related to GH78. To which of the following is IJ90 related?`, o: [`KL12`, `JK01`, `LM23`, `MN12`], e: `Given: AB12 is related to CD34 and EF56 is related to GH78 with same logic. Logic: Letters are increasing + 2 and numbers are increasing + 22 place. For, AB12 - CD34 A + 2 = C, B + 2 = D 12 + 22 = 34 For, EF56 - GH78 E + 2 = G, F + 2 = H 56 + 22 = 78 Similarly, IJ90 - ? I + 2 = K, J + 2 = L 90 + 22 = 12 (after 99, it cycles back) So, IJ90 is related to KL12. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If \`A' means \`-', \`B' means \`÷', \`C' means \`×' and \`D' means \`+', then evaluate: 36 C 4 D 18 B 3 A 6 = ?`, o: [`146`, `150`, `144`, `148`], e: `Given: 36 C 4 D 18 B 3 A 6 = ? Given LettersABCD New Sign - ÷×+ Using BODMAS rule. Operation preference wise Symbol Brackets [], , () Orders, of (power), (root), of Division ÷ Multiplication × Addition + Subtraction - New equation: 36 × 4 + 18 ÷ 3 - 6 = ? 36 × 4 + 6 - 6 = ? 144 + 6 - 6 = ? ? = 144 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `What number completes the pattern: 4 2 = 12, 6 3 = 27, 8 4 = ?`, o: [`32`, `36`, `48`, `64`], e: `Given: 4 2 = 12, 6 3 = 27 Logic: (1st number + 2nd number) × 2nd number = 3rd number For, 4 2 = 12 (4 + 2) × 2 = 12 For, 6 3 = 27 (6 + 3) × 3 = 27 Similarly, 84=? (8 + 4) × 4 = 48 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `P is the sister of Q and Q is the father of R. What is P's relation to R?`, o: [`Aunt`, `Mother`, `Sister`, `Cousin`], e: `Given: P is the sister of Q and Q is the father of R. From the given information blood relation diagram will be. So, P is aunt of R. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Complete the series: 3, 7, 15, 31, ?`, o: [`47`, `63`, `61`, `59`], e: `Given: 3, 7, 15, 31, ? Logic: Numbers are multiply by 2 and + 1. 3×2+1=7 7 × 2 + 1 = 15 15 × 2 + 1 = 31 31 × 2 + 1 = 63 So, the missing term is 63. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Identify the next term: D4, G7, J10, ___`, o: [`L12`, `M13`, `N14`, `O15`], e: `Given: D4, G7, J10, ___ Logic: Letters and numbers are increasing + 3 place. D + 3 = G, G + 3 = J, J + 3 = M 4 + 3 = 7, 7 + 3 = 10, 10 + 3 = 13 So, the missing term is M13. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Painter : Canvas :: Writer : ___`, o: [`Paper`, `Pen`, `Book`, `Story`], e: `Given: Painter : Canvas :: Writer : ___ A painter works on a canvas. Similarly, Writer : ? A writer works on paper. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Identify the next number in the series: 4, 9, 15, 20, ___`, o: [`30`, `26`, `29`, `25`], e: `Given: 4, 9, 15, 20, ___ Logic: Numbers are increasing + 5 and + 6 place alternately. 4+5=9 9 + 6 = 15 15 + 5 = 20 20 + 6 = 26 So, the missing term is 26. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If \`#' means \`+', \`@' means \`×', \`$' means \`-' and \`%' means \`÷', then evaluate: 24 @ 5 # 10 $ 6 % 2 = ?`, o: [`130`, `124`, `127`, `120`], e: `Given: 24 @ 5 # 10 $ 6 % 2 = ? Given Symbol#@$% New Sign + × - ÷ Using BODMAS rule. Operation preference wise Symbol Brackets [], , () Orders, of (power), (root), of Division ÷ Multiplication × Addition + Subtraction - New equation: 24 × 5 + 10 - 6 ÷ 2 = ? 24 × 5 + 10 - 3 = ? 120 + 10 - 3 = ? 130 - 3 = ? ? = 127 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Which word does not belong to this set?`, o: [`January`, `March`, `July`, `Sunday`], e: `January, March and July are all months. Sunday is a day of the week, not a month. So, Sunday is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `If you accidentally damage a colleague's property at work, what is the most appropriate action?`, o: [`Ignore it`, `Blame someone else`, `Inform them and apologize`, `Replace it secretly`], e: `Given: If you accidentally damage a colleague's property at work. Explanation: Being honest and taking responsibility by informing your colleague and apologizing is the most appropriate and professional action. So, Inform them and apologize is the most appropriate action. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Which number does not belong?`, o: [`2`, `3`, `5`, `9`], e: `2, 3 and 5 are prime numbers. 9 is a composite number. So, 9 is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `If = 10, = 5, and = 3, what is ( - ) × ?`, o: [`10`, `12`, `15`, `18`], e: `Given: = 10, = 5, = 3 Expression: (( - ) × ) = ((10 - 5) × 3) =5×3 = 15 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Barometer is to Pressure as Speedometer is to ___?`, o: [`Distance`, `Speed`, `Time`, `Force`], e: `Given: Barometer is to Pressure as Speedometer is to ___? A barometer measures pressure. Similarly, A speedometer measures speed. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Doctor is to Hospital as Teacher is to:`, o: [`School`, `Student`, `Book`, `Education`], e: `Given: Doctor is to Hospital as Teacher is to: A doctor works in a hospital. Similarly, A teacher works in a school. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Choose the word that does not belong to the group.`, o: [`Table`, `Chair`, `Bed`, `Car`], e: `Table, Chair and Bed are all furniture items. Car is a vehicle, not furniture. So, Car is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `If 12 is to 36, then 15 is to ___?`, o: [`40`, `45`, `48`, `60`], e: `Given: If 12 is to 36, then 15 is to ___? 12 × 3 = 36 Similarly, 15 × 3 = 45 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `You find a wallet on the road containing cash and ID. What should you do?`, o: [`Keep the cash`, `Leave it there`, `Hand it to the police`, `Throw it away`], e: `Given: You find a wallet on the road containing cash and ID. Explanation: Handing the wallet to the police is the most honest and responsible action, as it gives the owner the best chance of getting it back safely. So, Hand it to the police should you do. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `A manager must choose between two plans: Plan A: Guaranteed profit of 50 units Plan B: 50% chance of 120 units profit and 50% chance of 0 profit Assuming risk-neutral behavior, which plan should be chosen?`, o: [`Plan A`, `Plan B`, `Both are equal`, `Cannot be decided`], e: `Given: A manager must choose between two plans: Plan A: Guaranteed profit of 50 units Plan B: 50% chance of 120 units profit and 50% chance of 0 profit Assuming risk-neutral behavior. Solution: Let's compare the expected profit of both plans. Plan A: Guaranteed profit = 50 units Plan B: 50% chance of 120 units 50% chance of 0 units Expected value of Plan B: (0.5× 120) + (0.5 × 0) = 60 Since 60 > 50, a risk-neutral manager will choose the plan with the higher expected value. So, Plan B should be chosen. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Pen is to Ink as Printer is to ___?`, o: [`Paper`, `Toner`, `Electricity`, `File`], e: `Given: Pen is to Ink as Printer is to ___? A pen uses ink to write. Similarly, A printer uses toner (or ink) to print. Thus, correct option is (b).` },
  { s: `General Awareness`, q: `Who presides over the Lok Sabha?`, o: [`President`, `Speaker`, `Prime Minister`, `Vice President`], e: `The correct answer is (B) Speaker Explanation: · The Speaker is the presiding officer of the Lok Sabha (Lower House of Parliament). · The Speaker is elected by the members of the Lok Sabha from among themselves. Information Booster: · The Speaker maintains order and decorum in the House and decides whether a bill is a Money Bill or not. Additional Knowledge: · President (Option A): The formal head of the executive branch. · Prime Minister (Option C): The leader of the majority party in the Lok Sabha. · Vice President (Option D): The ex-officio Chairman of the Rajya Sabha.` },
  { s: `General Awareness`, q: `Total supply of goods and services in an economy is called ______.`, o: [`Aggregate demand`, `Aggregate supply`, `Inflation`, `Fiscal deficit`], e: `The correct answer is (B) Aggregate supply Explanation: · Aggregate supply is the total volume of goods and services that producers in an economy are willing and able to supply at a given overall price level in a given time period. · It represents the productive capacity of the economy. Information Booster: · In the long run, aggregate supply is determined by factors of production like land, labor, and capital. Additional Knowledge: · Aggregate demand (Option A): The total demand for finished goods and services in an economy. · Inflation (Option C): A general increase in prices and fall in the purchasing value of money. · Fiscal deficit (Option D): The difference between the government's total expenditure and its total receipts (excluding borrowing).` },
  { s: `General Awareness`, q: `Which Article of the Indian Constitution abolishes untouchability?`, o: [`Article 17`, `Article 19`, `Article 21`, `Article 32`], e: `The correct answer is (A) Article 17 Explanation: · Article 17 of the Indian Constitution abolishes "Untouchability" and forbids its practice in any form. · The enforcement of any disability arising out of untouchability is an offence punishable in accordance with law. Information Booster: · The Untouchability (Offences) Act, 1955, was later renamed as the Protection of Civil Rights Act, 1955. Additional Knowledge: · Article 19 (Option B): Guarantees the Protection of six rights regarding freedom (speech, assembly, etc.). · Article 21 (Option C): Protection of life and personal liberty. · Article 32 (Option D): Right to Constitutional Remedies (the "Heart and Soul" of the Constitution).` },
  { s: `General Awareness`, q: `Which molecule carries genetic information from DNA to ribosomes?`, o: [`tRNA`, `rRNA`, `mRNA`, `DNA polymerase`], e: `The correct answer is (C) mRNA Explanation: · mRNA (messenger RNA) is a single-stranded molecule that carries genetic code from DNA in the nucleus to the ribosomes in the cytoplasm. · This process of copying genetic information from DNA to mRNA is called transcription. Information Booster: · The ribosome reads the mRNA sequence and translates it into a specific chain of amino acids to form a protein. Additional Knowledge: · tRNA (Option A): Transfers specific amino acids to the ribosome during protein synthesis. · rRNA (Option B): Forms the core of the ribosome's structure and catalyzes protein synthesis. · DNA polymerase (Option D): An enzyme responsible for synthesizing new DNA strands during replication.` },
  { s: `General Awareness`, q: `Which Mughal emperor built the Red Fort in Delhi?`, o: [`Akbar`, `Shah Jahan`, `Aurangzeb`, `Humayun`], e: `The correct answer is (B) Shah Jahan Explanation: · The Red Fort (Lal Qila) was commissioned by Emperor Shah Jahan in 1638 when he decided to shift his capital from Agra to Delhi. · It is named for its massive enclosing walls of red sandstone. Information Booster: · The architect of the Red Fort was Ustad Ahmad Lahauri, who also designed the Taj Mahal. Additional Knowledge: · Akbar (Option A): Built Fatehpur Sikri and Agra Fort. · Aurangzeb (Option C): Built the Badshahi Mosque and the Bibi Ka Maqbara. · Humayun (Option D): His tomb in Delhi is a major architectural landmark, though he did not build the Red Fort.` },
  { s: `General Awareness`, q: `Which medal is awarded for third position in the Olympic Games?`, o: [`Gold`, `Silver`, `Bronze`, `Platinum`], e: `The correct answer is (C) Bronze Explanation: · In the Olympic Games, the first, second, and third-place finishers are awarded Gold, Silver, and Bronze medals respectively. · The tradition of awarding medals began at the 1904 St. Louis Olympics. Information Booster: · Bronze is an alloy consisting primarily of copper, usually with about 12% tin. Additional Knowledge: · Gold (Option A): Awarded for 1st place. · Silver (Option B): Awarded for 2nd place. · Platinum (Option D): Not a standard Olympic medal category.` },
  { s: `General Awareness`, q: `Who wrote the famous literary work Gitanjali?`, o: [`Rabindranath Tagore`, `Munshi Premchand`, `Sarojini Naidu`, `Bankim Chandra Chatterjee`], e: `The correct answer is (A) Rabindranath Tagore Explanation: · Gitanjali is a collection of poems by the Bengali poet Rabindranath Tagore. · Tagore received the Nobel Prize in Literature in 1913, largely for this work. Information Booster: · Tagore was the first non-European to win a Nobel Prize in Literature. Additional Knowledge: · Munshi Premchand (Option B): Known as 'Upanyas Samrat', wrote Godan and Gaban. · Sarojini Naidu (Option C): Known as the 'Nightingale of India'. · Bankim Chandra Chatterjee (Option D): Famous for the patriotic song Vande Mataram.` },
  { s: `General Awareness`, q: `Which technology allows computers to understand human language?`, o: [`Natural Language Processing`, `Blockchain`, `Internet of Things`, `Cloud Computing`], e: `The correct answer is (A) Natural Language Processing Explanation: · Natural Language Processing (NLP) is a branch of artificial intelligence that gives computers the ability to understand, interpret, and generate human language. · It combines computational linguistics with statistical, machine learning, and deep learning models. Information Booster: · Virtual assistants like Alexa and Siri heavily rely on NLP technology. Additional Knowledge: · Blockchain (Option B): A distributed ledger technology most known for its role in cryptocurrency. · Internet of Things (Option C): The network of physical objects embedded with sensors and software for data exchange. · Cloud Computing (Option D): The on-demand delivery of computing services over the internet.` },
  { s: `General Awareness`, q: `Which city is known as the Pink City of India?`, o: [`Jaipur`, `Jodhpur`, `Udaipur`, `Bikaner`], e: `The correct answer is (A) Jaipur Explanation: · Jaipur is known as the "Pink City" because of the dominant color scheme of its buildings. · In 1876, Maharaja Sawai Ram Singh painted the whole city pink to welcome Prince Albert and Queen Victoria. Information Booster: · Jaipur is a UNESCO World Heritage site and is also famous for the Hawa Mahal. Additional Knowledge: · Jodhpur (Option B): Known as the Blue City or Sun City. · Udaipur (Option C): Known as the City of Lakes or the Venice of the East. · Bikaner (Option D): Known for its desert landscape and Bikaneri Bhujia.` },
  { s: `General Awareness`, q: `Who created the fictional detective Feluda?`, o: [`Rabindranath Tagore`, `Satyajit Ray`, `Bankim Chandra Chatterjee`, `Sarat Chandra Chattopadhyay`], e: `The correct answer is (B) Satyajit Ray Explanation: · Feluda is a fictional private investigator created by the renowned filmmaker and writer Satyajit Ray. · The character first appeared in the Bengali magazine Sandesh in 1965. Information Booster: · Feluda is accompanied by his cousin Topshe and the thriller writer Jatayu in most of the stories. Additional Knowledge: · Rabindranath Tagore (Option A): Author of Gitanjali and composer of India's national anthem. · Bankim Chandra Chatterjee (Option C): Author of Anandamath and Vande Mataram. · Sarat Chandra Chattopadhyay (Option D): Famous novelist known for Devdas and Pather Dabi.` },
  { s: `General Awareness`, q: `Movement of people into a country is called ______.`, o: [`Immigration`, `Emigration`, `Urbanization`, `Migration`], e: `The correct answer is (A) Immigration Explanation: · Immigration refers to the act of coming to live permanently in a foreign country. · It is the "inward" movement of people from one country to another. Information Booster: · The "push and pull" factors are major drivers of global migration patterns. Additional Knowledge: · Emigration (Option B): The act of leaving one's own country to settle permanently in another. · Urbanization (Option C): The process of making an area more urban (rural to city shift). · Migration (Option D): A general term for the movement of people from one place to another.` },
  { s: `General Awareness`, q: `Which mission promotes manufacturing in India?`, o: [`Digital India`, `Skill India`, `Make in India`, `Startup India`], e: `The correct answer is (C) Make in India Explanation: · Make in India was launched in 2014 to encourage companies to manufacture their products in India. · It aims to transform India into a global design and manufacturing hub. Information Booster: · The initiative covers 25 sectors of the economy, including automobiles, chemicals, and IT. Additional Knowledge: · Digital India (Option A): Aims to ensure government services are available to citizens electronically. · Skill India (Option B): Launched to empower the youth of the country with skill sets to make them more employable. · Startup India (Option D): Aims to foster entrepreneurship and promote innovation.` },
  { s: `General Awareness`, q: `Which classical dance form originated in Uttar Pradesh?`, o: [`Bharatanatyam`, `Kathak`, `Odissi`, `Kuchipudi`], e: `The correct answer is (B) Kathak Explanation: · Kathak is the classical dance form of North India, particularly originating and flourishing in Uttar Pradesh. · It is known for its intricate footwork and spins (chakkars). Information Booster: · The name Kathak is derived from the Sanskrit word 'Katha' which means story. Additional Knowledge: · Bharatanatyam (Option A): Originated in Tamil Nadu. · Odissi (Option C): Originated in Odisha. · Kuchipudi (Option D): Originated in Andhra Pradesh.` },
  { s: `General Awareness`, q: `Gandhara sculptures mainly used which type of stone?`, o: [`Granite`, `Grey schist`, `Marble`, `Basalt`], e: `The correct answer is (B) Grey schist Explanation: · The Gandhara School of Art used grey schist and stucco for creating sculptures, primarily of the Buddha. · This school flourished during the Kushana period and shows heavy Greek and Roman influence. Information Booster: · The Gandhara art is often called Greco-Buddhist art. Additional Knowledge: · Granite (Option A): Used extensively in the construction of temples in South India (e.g., Chola temples). · Marble (Option C): Used predominantly in Mughal architecture, especially during Shah Jahan's reign. · Basalt (Option D): Common in the rock-cut cave temples of the Deccan, such as Ajanta and Ellora.` },
  { s: `General Awareness`, q: `Mudra Yojana mainly provides loans to ______.`, o: [`Farmers`, `Students`, `Small entrepreneurs`, `Government employees`], e: `The correct answer is (C) Small entrepreneurs Explanation: · Pradhan Mantri MUDRA Yojana (PMMY) provides loans up to 10 lakh to non-corporate, non-farm small/micro-enterprises. · These loans are classified as Shishu, Kishore, and Tarun. Information Booster: · MUDRA stands for Micro Units Development & Refinance Agency Ltd. Additional Knowledge: · Farmers (Option A): Supported by Kisan Credit Cards and PM-KISAN. · Students (Option B): Assisted through various education loan interest subsidy schemes like CSIS. · Government employees (Option D): Usually have access to specific GPF advances and department-specific loan schemes.` },
  { s: `General Awareness`, q: `Headquarters of UNESCO is located in which city?`, o: [`Geneva`, `Paris`, `Vienna`, `Rome`], e: `The correct answer is (B) Paris Explanation: · The United Nations Educational, Scientific and Cultural Organization (UNESCO) is headquartered in Paris, France. · It aims to promote world peace and security through international cooperation in education, arts, sciences, and culture. Information Booster: · UNESCO was founded on 16 November 1945. Additional Knowledge: · Geneva (Option A): Headquarters of WHO, WTO, and ILO. · Vienna (Option C): Headquarters of IAEA and OPEC. · Rome (Option D): Headquarters of FAO.` },
  { s: `General Awareness`, q: `Which government scheme provides LPG connections to poor households?`, o: [`Ujjwala Yojana`, `PM Awas Yojana`, `PM Kisan Samman Nidhi`, `Jan Dhan Yojana`], e: `The correct answer is (A) Ujjwala Yojana Explanation: · Pradhan Mantri Ujjwala Yojana (PMUY) was launched in 2016 to provide clean cooking fuel (LPG) to women in BPL (Below Poverty Line) households. · Its goal is to safeguard the health of women and children by providing them with a clean cooking fuel. Information Booster: · The second phase of the scheme, Ujjwala 2.0, was launched in 2021 to provide additional 1 crore LPG connections. Additional Knowledge: · PM Awas Yojana (Option B): Aims to provide affordable housing for the urban and rural poor. · PM Kisan (Option C): Provides income support of 6,000 per year to all landholding farmer families. · Jan Dhan Yojana (Option D): A national mission for financial inclusion to ensure access to financial services.` },
  { s: `General Awareness`, q: `Which river is associated with the Narmada Bachao Andolan?`, o: [`Godavari`, `Narmada`, `Krishna`, `Tapti`], e: `The correct answer is (B) Narmada Explanation: · Narmada Bachao Andolan (NBA) is a social movement against a number of large dams being built across the Narmada River. · Key figures in this movement include Medha Patkar and Baba Amte. Information Booster: · The Sardar Sarovar Dam is the largest dam built on the Narmada River. Additional Knowledge: · Godavari (Option A): Known as the Dakshina Ganga. · Krishna (Option B): One of the longest rivers in India, originating at Mahabaleshwar. · Tapti (Option D): A west-flowing river that runs parallel to the Narmada.` },
  { s: `General Awareness`, q: `Which index measures poverty across multiple dimensions?`, o: [`Human Development Index`, `Multidimensional Poverty Index`, `Global Hunger Index`, `Consumer Price Index`], e: `The correct answer is (B) Multidimensional Poverty Index Explanation: · The Multidimensional Poverty Index (MPI) measures acute poverty by considering health, education, and living standards. · It identifies deprivations beyond just income levels. Information Booster: · It was developed in 2010 by the Oxford Poverty and Human Development Initiative (OPHI) and the UNDP. Additional Knowledge: · Human Development Index (Option A): A summary measure of average achievement in key dimensions of human development. · Global Hunger Index (Option C): A tool that measures and tracks hunger globally, regionally, and by country. · Consumer Price Index (Option D): A measure that examines the weighted average of prices of a basket of consumer goods and services.` },
  { s: `General Awareness`, q: `Which port is known as the "Gateway of India"?`, o: [`Chennai Port`, `Mumbai Port`, `Paradip Port`, `Kochi Port`], e: `The correct answer is (B) Mumbai Port Explanation: · Mumbai Port has historically been the primary port of India, earning the title "Gateway of India" due to its strategic location on the western coast. · It is one of the oldest and most important commercial ports in the country. Information Booster: · Jawaharlal Nehru Port (JNPT), also in Mumbai, is the largest container port in India. Additional Knowledge: · Chennai Port (Option A): One of the largest ports in the Bay of Bengal. · Paradip Port (Option C): A major deep-sea port in Odisha. · Kochi Port (Option D): A major port on the Arabian Sea­Indian Ocean sea route in Kerala.` },
  { s: `General Awareness`, q: `Which Indian state hosts the Muppandal Wind Farm, one of the largest wind farms in India?`, o: [`Gujarat`, `Tamil Nadu`, `Maharashtra`, `Karnataka`], e: `The correct answer is (B) Tamil Nadu Explanation: · The Muppandal Wind Farm is located in the Kanyakumari district of Tamil Nadu. · It is the largest operational onshore wind farm in India and one of the largest in the world. Information Booster: · India ranks 4th globally in terms of installed wind power capacity as of 2025-2026. Additional Knowledge: · Gujarat (Option A): Home to the Jaisalmer Wind Park (mostly in Rajasthan, but Gujarat has high capacity) and the Kutch renewable energy projects. · Maharashtra (Option C): Significant wind energy production at sites like Vankusawade. · Karnataka (Option D): Features large wind farms in the Tuppadahalli region.` },
  { s: `General Awareness`, q: `Which of the following is a scalar quantity?`, o: [`Velocity`, `Acceleration`, `Speed`, `Force`], e: `The correct answer is (C) Speed Explanation: · A scalar quantity is a physical quantity that is described by its magnitude (size) only, with no direction. · Speed measures how fast an object is moving but does not specify where it is going. Information Booster: · Vector quantities require both magnitude and direction to be fully defined. Additional Knowledge: · Velocity (Option A): A vector quantity defined as the rate of change of displacement. · Acceleration (Option B): A vector quantity representing the rate of change of velocity. · Force (Option D): A vector quantity defined as an interaction that changes the motion of an object.` },
  { s: `General Awareness`, q: `Which galaxy is closest to the Milky Way galaxy?`, o: [`Andromeda`, `Triangulum`, `Whirlpool`, `Sombrero`], e: `The correct answer is (A) Andromeda Explanation: · The Andromeda Galaxy (M31) is a spiral galaxy approximately 2.5 million light-years from Earth. · It is the largest galaxy of the Local Group, which also contains the Milky Way. Information Booster: · The Milky Way and Andromeda are expected to collide in about 4.5 billion years to form a giant elliptical galaxy. Additional Knowledge: · Triangulum (Option B): The third-largest member of the Local Group. · Whirlpool (Option C): A classic spiral galaxy in the constellation Canes Venatici. · Sombrero (Option D): A bright galaxy in the constellation Virgo known for its large central bulge.` },
  { s: `General Awareness`, q: `Which planet is known as the Evening Star?`, o: [`Venus`, `Mars`, `Jupiter`, `Mercury`], e: `The correct answer is (A) Venus Explanation: · Venus is often referred to as the "Evening Star" or "Morning Star" because it is one of the brightest objects in the sky after the Sun and Moon. · It appears shortly after sunset or shortly before sunrise. Information Booster: · Venus is also known as Earth's Twin due to its similar size and density. Additional Knowledge: · Mars (Option B): Known as the Red Planet. · Jupiter (Option C): The largest planet in our solar system. · Mercury (Option D): The smallest planet and closest to the Sun.` },
  { s: `General Awareness`, q: `Which cricket tournament is played between Indian states?`, o: [`Ranji Trophy`, `IPL`, `Asia Cup`, `Champions Trophy`], e: `The correct answer is (A) Ranji Trophy Explanation: · The Ranji Trophy is the premier domestic first-class cricket championship in India. · It is played between teams representing regional and state cricket associations. Information Booster: · The tournament is named after the first Indian cricketer wCohpoyprilgayhetd©in2t0e2rn6aAtidodnaa2l 4cr7icket, Ranjitsinhji. Additional Knowledge: · IPL (Option B): A professional T20 league based on city franchises. · Asia Cup (Option C): An international cricket tournament between Asian countries. · Champions Trophy (Option D): A major international ODI tournament organized by the ICC.` },
  { s: `Quantitative Aptitude`, q: `The population of a town is 15,000. If it increases by 20% the first year and decreases by 10% the next year, what is the population after 2 years?`, o: [`16,500`, `16,200`, `15,800`, `17,000`], e: `Given: Initial Population (P) = 15,000 Increase (R1) = 20% Decrease (R2) = 10% Formula Used: R1 R2 Final Population = P × (1 + ) × (1 - ) 100 100 Solution: Final Population = 15000 × 1.20 × 0.90 Final Population = 15000 ×1 .08 = 16,200 So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If the volume of a rectangular parallelepiped is 450 cm³ and its base area is 50 cm², what is its height?`, o: [`7 cm`, `8 cm`, `9 cm`, `10 cm`], e: `Given: Volume = 450 cm³ Base Area = 50 cm² Formula Used: Volume = Base Area × Height Solution: V olume 450 Height = = = 9 cm BaseArea 50 So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `How many natural numbers are there between 14² and 15²?`, o: [`27`, `30`, `29`, `28`], e: `Given: Numbers:142 and 152 Formula Used: Number of natural numbers between n2and(n + 1)2 is 2n. Solution: Here, n = 14. Number of natural numbers = 2 × 14 = 28 Alternatively, 152 - 142 - 1 = 225 - 196 - 1 = 28 So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `From a point P, a tangent is drawn to a circle with center O. The radius is 8 cm, and the distance from O to P is 17 cm. What is the length of the tangent?`, o: [`12 cm`, `15 cm`, `18 cm`, `20 cm`], e: `Given: Radius (r) = 8 cm Distance OP (d) = 17 cm Formula Used: Tangent length (t) = d2 - r2 Solution: t= 172 - 82 = 289 - 64 = 225 = 15cm So the correct answer is (b).` },
  { s: `Quantitative Aptitude`, q: `The average weight of 4 students is 50 kg. If one more student weighing 60 kg joins, what is the new average weight?`, o: [`51 kg`, `53 kg`, `52 kg`, `54 kg`], e: `Given: Average weight of 4 students = 50 kg. Weight of new student = 60 kg. Formula Used: New Average = Old Sum + New Value New Count Solution: Sum of weights of 4 students = 4 \\times 50 = 200 kg. New sum = 200 + 60 = 260 kg. New count = 4 + 1 = 5. New average = 260 / 5 = 52 kg. So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A sum fetches 3,600 as interest in 4 years at 6% per annum. What is the principal?`, o: [`12,000`, `14,000`, `15,000`, `16,000`], e: `Given: Simple Interest (SI) = 3,600 Time (T) = 4 years Rate (R) = 6% Formula Used: SI × 100 Principal (P) = R×T Solution: 3600 × 100 360000 P= = = 15000 6×4 24 So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `A submarine was navigating at a depth of -45 meters below sea level. It then ascended 20 meters towards the surface. What is its new position relative to sea level?`, o: [`- 25 meters`, `- 65 meters`, `+ 25 meters`, `- 20 meters`], e: `Given: Initial depth = -45 meters Ascent = +20 meters Formula Used: New Position = Initial Position + Change in Position Solution: New Position = -45 + 20 = -25 meters. Final Answer: So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `In a town, there are 3,800 females for every 4,000 males. What is the sex ratio in this town (number of females per 1000 males)?`, o: [`920`, `940`, `950`, `960`], e: `Given: Females = 3800 Males = 4000 Formula Used: Sex Ratio = Number of Females × 1000 Number of Males Solution: Ratio = 3800 × 1000= 3800 / 4 = 950 4000 So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `A triangle has sides 5 cm, 12 cm, and 13 cm. What type of triangle is this?`, o: [`Acute`, `Obtuse`, `Right-angled`, `Equilateral`], e: `Given: Sides: a = 5, b = 12, c = 13. Formula Used: Pythagorean theorem converse: If a2 + b2 = c2, the triangle is right-angled. Solution: 52 + 122 = 25 + 144 = 169 Since 25 + 144 = 169, it is a right-angled triangle. So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `A cone and a cylinder have the same radius and height. The ratio of their volumes is:`, o: [`1:2`, `1:3`, `2:3`, `3:4`], e: `Given: Radius of cone = Radius of cylinder = r. Height of cone = Height of cylinder = h. Formula Used: Volume of Cone = 1 r2h 3 Volume of Cylinder = r2h Solution: [Image showing a cone inscribed inside a cylinder with the same base and height] 1 r 2 h 1 3 or1 : 3 Ratio = r2h = 3 So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `In a bag of candies, 45% are red and 30% are blue. What percentage are green?`, o: [`20%`, `25%`, `30%`, `35%`], e: `Given: Red = 45% Blue = 30% Assuming the rest are green. Formula Used: Total percentage = 100% Solution: Green % = 100% - (Red % + Blue %) Green % = 100% - (45% + 30%) = 100% - 75% = 25%. Final Answer: So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A shop offers two successive discounts on a product: the first is 15%, and the second is 10%. What is the single equivalent discount percentage?`, o: [`23.5%`, `24.0%`, `24.5%`, `25.0%`], e: `Given: D1 = 15% D2 = 10% Formula Used: Equivalent Discount = D1 + D2 - D1 × D2 100 Solution: 15 10 15 × 10 Equivalent Discount = 15 + 10 - 100 = 25 - 1.5 = 23.5%. So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A merchant buys 50 mugs for 2,000. He sells 30 of them at 50 each and the remaining at 35 each. What is his profit or loss percentage?`, o: [`8%`, `10%`, `12%`, `15%`], e: `Given: Total Cost Price (CP) = 2,000 for 50 mugs. Selling Price (SP) of 30 mugs = 30 ×50 = 1,500 Selling Price (SP) of remaining 20 mugs = 20 ×35 = 700 Formula Used: Total SP = SP1 + SP2 Profit = Total SP - Total CP Profit % = (Profit / CP) ×100 Solution: Total SP = 1500 + 700 = 2,200. Profit = 2200 - 2000 = 200. Profit % = 200 × 100 = 10% 2000 So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A bus takes 8 hours to cover a distance of 400 km. If its speed is increased by 30 km/h, how much time will it take?`, o: [`4 hours`, `5 hours`, `6 hours`, `7 hours`], e: `Given: Initial Time (T1) = 8 hours Distance (D) = 400 km Speed increase = 30 km/h Formula Used: Speed = Distance Time T ime = Distance Speed Solution: Initial Speed (S1) = 400 / 8 = 50 km/h New Speed (S2) = 50 + 30 = 80 km/h New Time (T2) = 400 / 80 = 5 hours So the correct answer is (b).` },
  { s: `Quantitative Aptitude`, q: `The average of a set of 10 numbers is 45. If one number, 60, is replaced by 40, what is the new average?`, o: [`41`, `42`, `43`, `44`], e: `Given: Count (n) = 10 Old Average = 45 Replaced value = 60, New value = 40 Formula Used: New Average = Old Average + New Value - Old Value n Solution: Change in sum = 40 - 60 = -20. Change in average = -20 / 10 = -2. New Average = 45 - 2 = 43 Final Answer: So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `A recipe needs 4 cups of sugar to make 18 cookies. How many cups of sugar are needed to make 27 cookies in the same proportion?`, o: [`5 cups`, `6 cups`, `7 cups`, `8 cups`], e: `Given: 4 cups sugar 1 8 cookies. x cups sugar 27 cookies. Formula Used: x x 1 2 Direct Proportion: = y1 y2 Solution: 4x = 18 27 4× 27 108 x = = 18 18 x = 6 cups So the correct answer is (b).` },
  { s: `Quantitative Aptitude`, q: `What is 137/11 as a mixed number? 5`, o: [`12`, `11`, `12`, `11`], e: `Given: Fraction: 137/11 Formula Used: Dividend = Quotient × Divisor + Remainder Solution: Divide 137 by 11. 137 = 11 \\times 12 + 5 Quotient = 12, Remainder = 5. 5 Mixed number = 12 11 So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A bakery uses 24.6 kilograms of flour each day. On Monday, it used only 1/2 of the daily amount. On Tuesday, it used 20% more than it did on Monday. How much flour was used in total over the two days?`, o: [`27.06 kilograms`, `28.50 kilograms`, `26.04 kilograms`, `25.50 kilograms`], e: `Given: Standard daily amount = 24.6 kg Monday usage = 1/2 of daily amount Tuesday usage = 120% of Monday usage Solution: Monday usage = 24.6 / 2 = 12.3 kg Tuesday usage = 12.3 ×1.20 = 14.76 kg Total usage = 12.3 + 14.76 = 27.06 kg So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Which number set includes all rational and irrational numbers?`, o: [`Natural numbers`, `Whole numbers`, `Real numbers`, `Complex numbers`], e: `Given: Sets of numbers: Rational and Irrational. Formula Used: Real numbers = Rational numbers $\\cup$ Irrational numbers. Solution: The set that contains both rational and irrational numbers is the set of Real numbers. So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A train travels 240 km in 4 hours. What is its speed?`, o: [`55 km/h`, `60 km/h`, `65 km/h`, `70 km/h`], e: `Given: Distance = 240 km Time = 4 hours Formula Used: Speed = Distance / Time Solution: Speed = 240 / 4 = 60 km/h So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A dealer allows a 20% discount on the marked price and still makes a profit of 12%. If the cost price of the article is 1,500, what is the marked price?`, o: [`1,900`, `2,000`, `2,100`, `2,200`], e: `Given: Discount (D) = 20% Profit (P) = 12% Cost Price (CP) = 1,500 Formula Used: M P 100 + P % = CP 100 - D% Solution: M P 100 + 12 112 = = 1500 100 - 20 80 112 M P = 1500 × = 1500 × 1.4 = 2, 100 80 So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `What is the selling price if the cost price is 600 and the profit is 15%?`, o: [`675`, `690`, `700`, `715`], e: `Given: Cost Price (CP) = 600 Profit % = 15% Formula Used: Selling Price (SP) = CP × (1 + Profit % ) 100 Solution: SP = 600 \\times (1 + 0.15) = 600 ×1.15 = 690. Final Answer: So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `P and Q complete a work in 16 days. Q alone takes 24 days. In how many days will P alone complete the work?`, o: [`48 days`, `50 days`, `42 days`, `54 days`], e: `Given: Time taken by (P + Q) = 16 days. Time taken by Q = 24 days. Formula Used: 1 1 1 = - P P +Q Q Solution: 1 1 1 3-2 1 = - = = P 16 24 48 48 P alone will take 48 days. Final Answer: So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A solid cylinder is melted and recast into smaller cylinders of the same height but one-third the radius. How many smaller cylinders can be made?`, o: [`3`, `6`, `9`, `12`], e: `Given: Original cylinder: radius R, height H. Smaller cylinder: radius r = R/3, height h = H. Formula Used: Volume = R2H Volume of large cylinder Number of cylinders = Volume of small cylinder Solution: Volume of large cylinder = R2H R2 R2 Volume of small cylinder = ( ) H = H 3 9 R2H Number = (R2/9)H = 9 Final Answer: So the correct answer is (c).` },
  { s: `Quantitative Aptitude`, q: `X and Y can complete a work in 10 days. Y alone can do it in 15 days. In how many days will X alone complete the work?`, o: [`25 days`, `30 days`, `35 days`, `40 days`], e: `Given: Time taken by (X + Y) = 10 days. Time taken by Y = 15 days. Formula Used: 1 1 1 = - X X+Y Y Solution: 1 1 1 3-2 1 = - = = X 10 15 30 30 X alone will take 30 days. So the correct answer is (b)` },
  { s: `English Language`, q: `Fill in the blank with most appropriate option: He was __ nervous to walk up on stage and perform.`, o: [`somewhat`, `fairly`, `too`, `quite`], e: `ExplanationThe correct option to fill in the blank is (c) too. The sentence follows the grammatical structure 'too + adjective + to- infinitive', which indicates a higher degree than is desirable or possible for a particular action. ( ) Grammatical Rule Used The adverb 'too' is used before adjectives or adverbs to mean 'more than is necessary or good'. It is frequently paired with 'to' + verb (infinitive) to express a negative consequence or a limit. Example: The tea is too hot to drink. Why other options are incorrect somewhat: Means to a moderate extent or degree. It does not typically pair with the 'to + verb' structure in this specific idiomatic way. ( ) fairly: Used to mean moderately or to a certain degree, usually with positive adjectives; it doesn't fit the 'too...to' resultative c` },
  { s: `English Language`, q: `Identify the antonym of "Denounce":`, o: [`Approve`, `Criticise`, `Rebuke`, `Condemn`], e: `ExplanationThe correct antonym of the given word is (a) Approve. Denounce: To publicly declare to be wrong or evil; to inform against someone or criticize someone/something harshly. ( / ) Example: The government was quick to denounce the terrorist attack. Approve: To officially agree to or accept as satisfactory; to have a positive opinion of someone or something. ( / ) Example: The committee is likely to approve the new budget proposal. Synonyms: Condemn, Criticize, Attack, Vilify. Antonyms: Approve, Praise, Commend, Support. Meanings of all the other given options Criticise: To indicate the faults of someone or something in a disapproving way. ( ) Rebuke: To express sharp disapproval or criticism of someone because of their actions. () Condemn: To express complete disapproval of; typical` },
  { s: `English Language`, q: `Identify the synonym of 'Zenith':`, o: [`Peak`, `Descent`, `Bottom`, `Valley`], e: `ExplanationThe correct synonym of the given word is (a) Peak. Zenith: The time at which something is most powerful or successful; the highest point reached by an object. ( / ) Example: At the zenith of his career, he was the most famous actor in the world. Peak: The pointed top of a mountain or the highest, strongest, or best point/level of something. (/) Example: Traffic reaches its peak between 8 and 9 in the morning. Synonyms: Acme, Summit, Apex, Pinnacle. Antonyms: Nadir, Bottom, Base, Depth. Meanings of all the other given options Descent: An action of moving downwards, dropping, or falling. (/) Bottom: The lowest point or part of something. (/ ) Valley: A low area of land between hills or mountains. () So the correct answer is (a)` },
  { s: `English Language`, q: `Identify the synonym of 'Xenial'`, o: [`Hospitable`, `Hostile`, `Indifferent`, `Reclusive`], e: `ExplanationThe correct synonym of the given word is (a) Hospitable. Xenial: Relating to the relations between a host and guest, especially the custom of offering hospitality to strangers. (- ) Example: The villagers were known for their xenial nature toward travelers. Hospitable: Friendly and welcoming to visitors or guests. (/) Example: The local people are very hospitable and kind to tourists. Synonyms: Welcoming, Friendly, Amiable, Cordial. Antonyms: Hostile, Inhospitable, Unfriendly, Receptive. Meanings of all the other given options Hostile: Unfriendly; antagonistic or showing strong opposition. () Indifferent: Having no particular interest or sympathy; unconcerned. () Reclusive: Avoiding the company of other people; solitary. (/) So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: They set up their camp (1) / besides the river (2) / and spent (3) / the entire night there (4).`, o: [`They set up their camp (1)`, `besides the river (2)`, `and spent (3)`, `the entire night there. (4)`], e: `ExplanationOption (b) contains an error. The word 'besides' is used incorrectly in this context. 'Besides' means 'in addition to' or 'apart from', whereas 'beside' means 'at the side of' or 'next to'. Since the sentence refers to the location of the camp relative to the river, 'beside' should be used. Grammatical Rule Used Confusing prepositions: Beside vs Besides. Use 'Beside' for physical proximity (next to). Use 'Besides' to mean 'in addition to'. Example: He sat beside me in the class. (Next to me) Besides milk, we need bread. (In addition to milk) Information Booster Always check the context for physical position vs. additional information when choosing between 'beside' and 'besides'. So the correct answer is (b)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The furniture (1) / in that old room are (2) / quite worn out (3) / and dusty (4).`, o: [`The furniture (1)`, `in that old room are (2)`, `quite worn out (3)`, `and dusty. (4)`], e: `ExplanationOption (b) contains an error. The noun 'furniture' is an uncountable noun. In English grammar, uncountable nouns are always treated as singular and take a singular verb. Therefore, 'are' should be replaced with 'is'. Grammatical Rule Used Subject-Verb Agreement: Uncountable nouns (like furniture, advice, information, luggage, equipment) always take a singular verb. Example: The information is correct (Not: are correct). Information Booster To make 'furniture' plural in sense, we use phrases like 'items of furniture' or 'pieces of furniture'. So the correct answer is (b)` },
  { s: `English Language`, q: `Identify the antonym of "Taciturn":`, o: [`Garrulous`, `Reticent`, `Introverted`, `Withdrawn`], e: `ExplanationThe correct antonym of the given word is (a) Garrulous. Taciturn: (of a person) reserved or uncommunicative in speech; saying little. (/ ) Example: He was a taciturn man who rarely shared his feelings with others. Garrulous: Excessively talkative, especially on trivial matters. (/) Example: The garrulous neighbor kept us at the gate for an hour talking about the weather. Synonyms: Reserved, Reticent, Silent, Quiet. Antonyms: Garrulous, Loquacious, Talkative, Outgoing. Meanings of all the other given options Reticent: Not revealing one's thoughts or feelings readily. ( ) Introverted: A person who is shy or reticent. () Withdrawn: Not wanting to communicate with other people. (-/) So the correct answer is (a)` },
  { s: `English Language`, q: `Pick the correctly spelled word:`, o: [`Occurence`, `Occurance`, `Occurrence`, `Occurrance`], e: `ExplanationOption (c) is the correctly spelt word. Correct spelling is: "Occurrence" which means an incident or event; the fact or frequency of something happening. (/) Example: The occurrence of such natural disasters has increased in recent years. Analysis of parts of speech The word 'Occurrence' is a Noun. It is derived from the verb 'occur'. When 'occur' (ending in a consonant-vowel-consonant with stress on the last syllable) takes a suffix starting with a vowel, the final consonant 'r' is doubled. Meanings of all the given options Occurence: Incorrect spelling. Occurance: Incorrect spelling. Occurrence: Correct spelling (An event or incident). Occurrance: Incorrect spelling. So the correct answer is (c)` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "A written law formally enacted by a legislative body."`, o: [`Ordinance`, `Statute`, `Manifesto`, `Decree`], e: `ExplanationThe correct one-word for the given group of words is (b) Statute. Statute: A formal written enactment of a legislative authority that governs a state, city, or country. (/) Example: The protection of these animals is guaranteed by federal statute. Meanings of the given other options Ordinance: An authoritative order or a decree; often a local law or regulation. () Manifesto: A public declaration of policy and aims, especially one issued before an election by a political party. () Decree: An official order that has the force of law, often issued by a legal authority or head of state. (/) So the correct answer is (b)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) He placed the vegetables in the pan and stirred gently. (2) He washed and chopped the vegetables carefully. (3) He served the dish on a plate and sat down to eat. (4) He lit the stove and added a little oil to the pan.`, o: [`2 - 1 - 4 - 3`, `2 - 4 - 1 - 3`, `4 - 2 - 1 - 3`, `1 - 2 - 3 - 4`], e: `Explanation Option (b) is the correct order of the given sentences. Grammatical Logic The sequence follows a chronological order of events in a cooking process. We use the Past Simple tense throughout to describe completed actions in a sequence. Typically, preparation precedes cooking, and cooking precedes serving. So the correct answer is (b) Sentence (2) is the logical starting point as it describes the initial preparation (washing and chopping). Sentence (4) follows, describing the next step of lCigohptiynrgigthhte©st2o0v2e6aAndddpar2e4p7aring the pan. Sentence (1) describes the actual cooking process (placing vegetables in the pan). Sentence (3) is the concluding action where the dish is served and eaten.` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "A person who studies the origin and historical development of words."`, o: [`Etymologist`, `Anthropologist`, `Philatelist`, `Lexicographer`], e: `ExplanationThe correct one-word for the given group of words is (a) Etymologist. Etymologist: A person who studies the history of words, their origins, and how their form and meaning have changed over time. (-) Example: As an etymologist, she spent years tracing the roots of common English idioms. Meanings of the given other options Anthropologist: A person who studies human societies and cultures and their development. () Philatelist: A person who collects or studies stamps. ( ) Lexicographer: A person who compiles or writes dictionaries. () So the correct answer is (a)` },
  { s: `English Language`, q: `Fill in the blank with most appropriate option: This road is __ than the one we took on our last trip.`, o: [`narrow`, `narrower`, `narrowest`, `more narrow`], e: `ExplanationThe correct option to fill in the blank is (b) narrower. The sentence uses the word 'than', which indicates a comparison between two things (this road and the previous road). Therefore, the comparative degree of the adjective 'narrow' must be used. Grammatical Rule Used When comparing two things, we use the comparative degree. For most one or two-syllable adjectives ending in 'w' or 'y', we add the suffix '-er'. Example: My house is bigger than yours. Why other options are incorrect narrow: This is the positive degree, used when no comparison is made. () narrowest: This is the superlative degree, used to compare more than two things. ( ) more narrow: While sometimes used, 'narrower' is the standard and preferred comparative form for this adjective. Information Booster Always loo` },
  { s: `English Language`, q: `Fill in the blank with most appropriate option: She delivered her speech __ clearly, earning applause from the audience.`, o: [`much`, `vary`, `more`, `quite`], e: `ExplanationThe correct option to fill in the blank is (d) quite. In this context, 'quite' is used as an adverb of degree to emphasize that she delivered her speech very clearly. ( ) Grammatical Rule Used 'Quite' is an adverb of degree that means 'to a certain extent' or 'very'. It can modify adjectives or other adverbs (like 'clearly'). Example: The task was quite difficult but manageable. Why other options are incorrect much: Typically used with comparative adjectives or in negative/interrogative sentences (e.g., 'much better'). It doesn't fit naturally before 'clearly' in this positive sentence. () vary: This is a verb, not an adverb, and thus grammatically incorrect here. (/ ) more: Used for comparison; since there is no 'than' or second entity being compared, it is incorrect. () Inform` },
  { s: `English Language`, q: `Which word is spelled correctly?`, o: [`Conscientious`, `Consientious`, `Consciencious`, `Conscientous`], e: `ExplanationOption (a) is the correctly spelt word. Correct spelling is: "Conscientious" which means wishing to do what is right, especially to do one's work or duty well and thoroughly. (/ ) Example: A conscientious teacher always prepares her lessCoonpsywrieglhl tin©ad2v0a2n6ceA.dda247 Analysis of parts of speech The word 'Conscientious' is an Adjective. It is derived from the noun 'conscience' (the moral sense of right and wrong). It ends with the suffix '-tious'. Meanings of all the given options Conscientious: Correct spelling (Governed by conscience). Consientious: Incorrect spelling (Missing 'c'). Consciencious: Incorrect spelling (Wrong suffix 'c'). Conscientous: Incorrect spelling (Missing 'i'). So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) She selected her preferred size and added the item to her cart. (2) She visited the website and browsed through the clothing section. (3) A confirmation message appeared on the screen once the order was placed. (4) She entered her payment details and clicked the 'Order Now' button.`, o: [`2-1-4-3`, `1-2-4-3`, `2-4-1-3`, `1-4-2-3`], e: `ExplanationOption (a) is the correct order of the given sentences. Sentence (2) sets the context by describing the first step of visiting the website and browsing. Sentence (1) follows as the next logical step--choosing a specific item and adding it to the cart. Sentence (4) describes the checkout process (entering details and ordering). Sentence (3) is the final outcome, receiving a confirmation. Grammatical Logic The paragraph describes a process (Online Shopping). The sentences are linked chronologically. Pronoun reference: 'The item' in sentence (1) refers to something found while 'browsing' in sentence (2). Similarly, sentence (3) mentions 'once the order was placed', which happens in sentence (4). So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) The machine dispensed the cash, and she collected it carefully. (2) She inserted her debit card into the ATM slot. (3) She selected the withdrawal option and entered the desired amount. (4) She entered her PIN number on the keypad.`, o: [`2-4-3-1`, `4-2-1-3`, `2-1-4-3`, `1-2-4-3`], e: `ExplanationOption (a) is the correct order of the given sentences. Sentence (2) is the starting action (inserting the card). Sentence (4) naturally follows, as the ATM requires a PIN immediately after card insertion. Sentence (3) describes the next interaction--selecting the transaction type and amount. Sentence (1) is the final step where the transaction is completed and cash is received. Grammatical Logic The sequence follows the standard operating procedure of an ATM. Grammatically, we use the Past Simple to narrate a series of finished events. The cohesion is maintained by the logical flow of a user's journey at a machine. So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the sentences correctly: (1) She grabbed her bag and rushed out of the house. (2) She prepared a quick breakfast in the kitchen. (3) She woke up to the sound of her alarm. (4) She reached the office just in time.`, o: [`3-1-2-4`, `2-3-1-4`, `1-2-3-4`, `3-2-1-4`], e: `ExplanationOption (d) is the correct order of the given sentences. Sentence (3) is the opening sentence, marking the beginning of the day (waking up). Sentence (2) is the subsequent activity (preparing breakfast). Sentence (1) follows, showing the transition from home to outside (leaving the house). Sentence (4) is the conclusion, showing the arrival at the destination (office). Grammatical Logic The order is strictly chronological. Coherence is established through a logical morning routine. We use the Past Simple for consecutive actions in a story. So the correct answer is (d)` },
  { s: `English Language`, q: `Fill in the blank with most appropriate option: No sooner had she opened the door __ the phone rang.`, o: [`than`, `when`, `then`, `as`], e: `ExplanationThe correct option to fill in the blank is (a) than. In English grammar, the correlative conjunction 'No sooner' is always paired with 'than' to indicate that one thing happens immediately after another. Grammatical Rule Used The structure is: No sooner + auxiliary verb + subject + vCeorbp.y..ri+ghtth©an2+02s6ubAjedcdta+24v7erb. 'No sooner' takes the comparative form 'than'. Example: No sooner had I reached the station than the train left. Information Booster Similarly, 'Scarcely' and 'Hardly' are always followed by 'when'. (e.g., Hardly had she reached when it started raining.) So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) The sapling grew into a beautiful tree over the years. (2) She dug a small hole in the ground. (3) She watered it every day with great care. (4) She placed the sapling gently into the hole.`, o: [`2-4-3-1`, `1-2-3-4`, `4-2-1-3`, `2-3-4-1`], e: `The correct answer is A. 2-4-3-1. Explanation The sequence describes the logical and chronological process of planting a tree. To solve sentence rearrangement (Para Jumbles) for competitive exams, you must look for the action-reaction or cause-effect relationship between sentences. (2) She dug a small hole in the ground: This is the foundational step. You cannot plant a sapling without first preparing the ground. (4) She placed the sapling gently into the hole: Once the hole is dug, the next logical action is to put the plant inside it. (3) She watered it every day with great care: After planting, the "it" (referring back to the sapling) requires maintenance and nourishment. (1) The sapling grew into a beautiful tree over the years: This is the final result of the previous actions, indicat` },
  { s: `English Language`, q: `Choose the correct meaning of the given idiom/phrase from the options: "Burn the midnight oil"`, o: [`To work or study very late into the night`, `To waste time on unimportant things`, `To celebrate a hard-earned victory`, `To cause unnecessary trouble`], e: `ExplanationOption (a) is the correct meaning of the given idiom. Burn the midnight oil: To work, study, or read late into the night. It originates from the time before electricity when people had to use oil lamps to see at night. ( ) Example: If you want to pass the exam with high marks, yoCuowpyilrlighhavte©to20b2u6rnAtdhdea2m4i7dnight oil. Other related idioms and their meanings Hit the books: To study very hard. Pull an all-nighter: To stay awake all night to study or work. Keep the candle burning at both ends: To work too hard without getting enough rest. So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The principal shared (1) / a important announcement (2) / with all the (3) / students present (4).`, o: [`The principal shared (1)`, `a important announcement (2)`, `with all the (3)`, `students present. (4)`], e: `ExplanationOption (b) contains an error. The indefinite article 'a' is used incorrectly before the word 'important'. Since 'important' begins with a vowel sound (//), the article 'an' should be used instead of 'a'. Grammatical Rule Used Article usage: Use 'an' before words that begin with a vowel sound (a, e, i, o, u). Use 'a' before words that begin with a consonant sound. Example: An apple, An honest man, A book, A university (starts with /j/ consonant sound). Information Booster Remember that the choice between 'a' and 'an' depends on the sound, not just the starting letter of the word. So the correct answer is (b)` },
  { s: `English Language`, q: `Fill in the blank with most appropriate phrasal verb: The candle flickered wildly in the wind, and she struggled to __ it __.`, o: [`blow -- out`, `set -- up`, `put -- off`, `turn -- over`], e: `ExplanationThe correct option to fill in the blank is (a) blow -- out. The phrasal verb 'blow out' means to extinguish a flame or fire by blowing. () Example: Make a wish before you blow out the candles. Why other options are incorrect set up: To establish or arrange something. ( ) put off: To delay or postpone. ( ) turn over: To flip something or transfer control. () Information Booster 'Put out' is another phrasal verb that means to extinguish, but 'blow out' specifically refers to the action of the wind or air. So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: He met (1) / a IAS officer (2) / at the seminar (3) / held last Friday (4).`, o: [`He met (1)`, `a IAS officer (2)`, `at the seminar (3)`, `held last Friday. (4)`], e: `ExplanationOption (b) contains an error. The acronym 'IAS' starts with the vowel sound /a/, so it should be preceded by the article 'an' instead of 'a'. Grammatical Rule Used Indefinite Articles with Abbreviations: If an abbreviation starts with a vowel sound (A, E, F, H, I, L, M, N, O, R, S, X), use 'an'. Example: An MLA, An FIR, An MP, but A BDO. Information Booster The sound is paramount. Even if a word starts with a consonant letter like 'H', if it is silent (e.g., hour), we use 'an'. So the correct answer is (b)` },
  { s: `English Language`, q: `Choose the correct meaning of the given idiom/phrase from the options: "Bite the bullet"`, o: [`To act in an aggressive manner`, `To endure a painful or difficult situation bravely`, `To give up on a task too easily`, `To make a decision in great haste`], e: `ExplanationOption (b) is the correct meaning of the given idiom. Bite the bullet: To accept or undergo something unpleasant or difficult that is otherwise unavoidable. It refers to historical times when soldiers had to bite on a bullet to endure pain during surgery without anesthesia. ( ) Example: I didn't want to go to the dentist, but I just had to bite the bullet and get it over with. Other related idioms and their meanings Face the music: To accept the unpleasant consequences of one's actions. Grit one's teeth: To keep one's resolve in a difficult situation. Take the bull by the horns: To deal with a difficult situation directly and courageously. So the correct answer is (b)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The manager was angry (1) / on the employee (2) / for reporting (3) / late to work (4).`, o: [`The manager was angry (1)`, `on the employee (2)`, `for reporting (3)`, `late to work. (4)`], e: `ExplanationOption (b) contains an error. The preposition 'on' is incorrectly used with the adjective 'angry'. In English grammar, when we are angry with a person, we use the preposition 'with'. If we are angry at a situation or something someone did, we use 'at'. Grammatical Rule Used Appropriate Prepositions: Angry with someone; Angry at/about something. Example: She was angry with her brother for breaking the vase. He was angry at the poor service in the restaurant. Information Booster Similar to 'angry', words like 'annoyed', 'displeased', and 'offended' also take 'with' for persons and 'at' for things. So the correct answer is (b)` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP-MAT' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Matriculation Level)',
      code: 'SSC-SSP-MAT',
      description: 'Staff Selection Commission - Selection Post (Matriculation Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Matriculation Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Matriculation) - 24 July 2025 Shift-1 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Matriculation', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '1',
    pyqExamName: 'SSC Selection Post Phase XIII (Matriculation) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
